// // โค้ด Base64 ที่ได้มาจะหน้าตาประมาณนี้ (ยาวมากๆ)
const String gifBase64 =
    "";

class UiverseLoader extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return Image.memory(base64Decode(gifBase64), scale: 5);
  }
}
